import{_ as e,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"13. No Further Claims","description":"","frontmatter":{"title":"13. No Further Claims","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/13-no-further-claims.md","filePath":"ebas/mental-health/common-terms/preliminary/13-no-further-claims.md"}'),n={name:"ebas/mental-health/common-terms/preliminary/13-no-further-claims.md"};function i(s,t,m,l,h,p){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="_13-no-further-claims" tabindex="-1">13. No Further Claims <a class="header-anchor" href="#_13-no-further-claims" aria-label="Permalink to &quot;13. No Further Claims&quot;">​</a></h1><p><strong>13.1</strong> The Parties acknowledge and agree that:</p><p><strong>(a)</strong> this Agreement settles all claims in relation to terms and conditions of employment of all Employees to whom it applies; and</p><p><strong>(b)</strong> that they will not pursue any extra claims during the term of this Agreement.</p><p><strong>13.2</strong> Subject to an Employer meeting its obligations to consult arising under this Agreement or a contract of employment binding on that Employer, it is not the intention of this provision to inhibit, limit or restrict an Employer&#39;s right to introduce change at the workplace.</p><p><strong>13.3</strong> The Parties agree to commence discussions no later than six months prior to the nominal expiry date of this Agreement. Clause 13.1 does not prevent a party from making a claim during the six-month period prior to the nominal expiry date of this Agreement.</p>',6)])])}const g=e(n,[["render",i]]);export{d as __pageData,g as default};
